/* Suggested markup: <div class="uiwiki-layered-date-composer" tabindex="0"><span>Layered Date Composer</span></div> */
.uiwiki-layered-date-composer {
  display: grid;
  place-items: center;
  min-height: 11rem;
  padding: 1.25rem;
  border: 1px solid #ececee;
  border-radius: 22px;
  background: #ffffff;
  color: #111111;
  font: 700 1rem/1.2 Inter, system-ui, sans-serif;
  box-shadow: 0 2px 16px rgba(0, 0, 0, 0.04);
  transition: transform 240ms cubic-bezier(.22, 1, .36, 1), box-shadow 240ms ease;
}
.uiwiki-layered-date-composer > span {
  padding: .75rem 1rem;
  border-radius: 999px;
  background: #f5e642;
  animation: layered_date_composer 1.8s ease-in-out infinite alternate;
}
.uiwiki-layered-date-composer:hover,
.uiwiki-layered-date-composer:focus-visible {
  transform: translateY(-3px);
  box-shadow: 0 10px 28px rgba(0, 0, 0, 0.08);
}
@keyframes layered_date_composer {
  from { transform: translateY(0) scale(1); }
  to { transform: translateY(-4px) scale(1.025); }
}
@media (prefers-reduced-motion: reduce) {
  .uiwiki-layered-date-composer, .uiwiki-layered-date-composer > span { animation: none; transition: none; }
}
